// Centralized Configuration Node
// All workflow settings are defined here for easy maintenance

const config = {
  // API Configuration
  api: {
    endpoints: [
      { id: '659', name: 'Brands Hatch' },
      { id: '660', name: 'Cadwell Park' },
      { id: '8034', name: 'Croft' },
      { id: '44', name: 'Donington Park' },
      { id: '39', name: 'Oulton Park' },
      { id: '8035', name: 'Silverstone' },
      { id: '2225', name: 'Snetterton' },
      { id: '657', name: 'Thruxton' },
      { id: '658', name: 'Mallory Park' },
      { id: '8033', name: 'Rockingham' }
    ],
    baseUrl: 'https://www.nolimitstrackdays.com',
    timeout: 15000,
    retryAttempts: 3,
    retryDelay: 2000
  },

  // Business Logic Configuration
  thresholds: {
    limitedSpaces: 10,
    criticalSpaces: 5
  },

  // Email Configuration
  email: {
    styles: {
      primaryColor: '#3498db',
      secondaryColor: '#2c3e50',
      successColor: '#27ae60',
      warningColor: '#f39c12',
      dangerColor: '#cc0000',
      lightBg: '#ecf0f1',
      darkBg: '#34495e'
    },
    dateFormat: {
      locale: 'en-GB',
      options: {
        weekday: 'long',
        year: 'numeric',
        month: 'short',
        day: 'numeric'
      }
    }
  },

  // Feature Flags
  features: {
    includeSummaryStats: true,
    includeBookingLinks: true,
    sortChronologically: true,
    highlightLimitedSpaces: true,
    mobileResponsive: true
  },

  // Validation Rules
  validation: {
    requiredFields: ['price', 'track', 'qty', 'url_key', 'description', 'date', 'group_value'],
    minPrice: 0,
    maxPrice: 10000
  }
};

return [{ json: { config } }];

// Validate API Response Node
// Ensures data quality before aggregation

try {
  const config = $('Configuration').item.json.config;
  const items = $input.all();
  const validatedItems = [];
  const errors = [];

  items.forEach((item, index) => {
    const data = item.json;

    // Check if response exists
    if (!data) {
      errors.push(`Item ${index}: No data received`);
      return;
    }

    // Check for track_days object
    if (!data.track_days || typeof data.track_days !== 'object') {
      // Empty response is valid (no events for this track)
      validatedItems.push({
        json: {
          ...data,
          track_days: {},
          validated: true,
          isEmpty: true
        }
      });
      return;
    }

    // Validate each event in track_days
    const trackDays = data.track_days;
    const validatedTrackDays = {};

    Object.keys(trackDays).forEach(key => {
      const event = trackDays[key];
      const missingFields = [];

      // Check required fields
      config.validation.requiredFields.forEach(field => {
        if (event[field] === undefined || event[field] === null) {
          missingFields.push(field);
        }
      });

      if (missingFields.length > 0) {
        errors.push(`Event ${key}: Missing fields: ${missingFields.join(', ')}`);
        return;
      }

      // Validate price range
      const price = Number(event.price);
      if (isNaN(price) || price < config.validation.minPrice || price > config.validation.maxPrice) {
        errors.push(`Event ${key}: Invalid price: ${event.price}`);
        return;
      }

      // Validate date format
      const eventDate = new Date(event.date);
      if (isNaN(eventDate.getTime())) {
        errors.push(`Event ${key}: Invalid date: ${event.date}`);
        return;
      }

      // Validate quantity
      const qty = Number(event.qty);
      if (isNaN(qty) || qty < 0) {
        errors.push(`Event ${key}: Invalid quantity: ${event.qty}`);
        return;
      }

      // Event passed validation
      validatedTrackDays[key] = event;
    });

    validatedItems.push({
      json: {
        ...data,
        track_days: validatedTrackDays,
        validated: true,
        isEmpty: Object.keys(validatedTrackDays).length === 0
      }
    });
  });

  // Log validation results
  console.log(`Validation complete: ${validatedItems.length} items validated`);
  if (errors.length > 0) {
    console.warn(`Validation warnings (${errors.length}):`, errors);
  }

  return validatedItems;

} catch (error) {
  console.error('Error in Validate API Response:', error.message);
  throw new Error(`API response validation failed: ${error.message}`);
}

// Define Events API Endpoints (Enhanced)
// Uses configuration from the Configuration node

try {
  const config = $('Configuration').item.json.config;

  if (!config || !config.api || !config.api.endpoints) {
    throw new Error('Configuration node not found or invalid');
  }

  const { endpoints, baseUrl } = config.api;

  // Build URLs from configuration
  const urls = endpoints.map(endpoint => ({
    json: {
      url: `${baseUrl}/tracks/api/get?product_id=${endpoint.id}`,
      trackName: endpoint.name,
      productId: endpoint.id
    }
  }));

  console.log(`Generated ${urls.length} API endpoints`);

  return urls;

} catch (error) {
  console.error('Error in Define Events API Endpoints:', error.message);
  throw new Error(`Failed to define API endpoints: ${error.message}`);
}

// Aggregate Events Data (Enhanced)
// Improved with error handling, validation, and chronological sorting

try {
  const config = $('Configuration').item.json.config;
  const LIMITED_SPACES_THRESHOLD = config.thresholds.limitedSpaces;
  const CRITICAL_SPACES_THRESHOLD = config.thresholds.criticalSpaces;

  const eventsData = {};
  const data = $input.all().map(item => item.json.track_days ?? {});

  // Statistics tracking
  let totalEvents = 0;
  let limitedSpacesCount = 0;
  let criticalSpacesCount = 0;
  const trackCount = {};

  // Parse all events
  data.forEach(track => {
    if (!Object.keys(track).length) return;

    const events = [];

    Object.keys(track).forEach(key => {
      try {
        const trackEvent = track[key];

        // Parse and validate event data
        const price = Number(trackEvent.price);
        const spaces = Number(trackEvent.qty);
        const eventDate = new Date(trackEvent.date);

        if (isNaN(price) || isNaN(spaces) || isNaN(eventDate.getTime())) {
          console.warn(`Skipping invalid event: ${key}`);
          return;
        }

        // Check if spaces are limited
        const limitedSpaces = spaces < LIMITED_SPACES_THRESHOLD;
        const criticalSpaces = spaces < CRITICAL_SPACES_THRESHOLD;

        // Update statistics
        totalEvents++;
        if (limitedSpaces) limitedSpacesCount++;
        if (criticalSpaces) criticalSpacesCount++;

        // Clean description (remove HTML tags and line breaks)
        const description = trackEvent.description
          .replace(/<[^>]*>/g, '')
          .replace(/[\r\n]/g, '')
          .trim();

        // Format friendly date
        const dateFriendly = eventDate.toLocaleDateString(
          config.email.dateFormat.locale,
          config.email.dateFormat.options
        );

        // Build booking URL
        const bookingUrl = `${config.api.baseUrl}/uk-tracks/${trackEvent.url_key}.html`;

        const newEvent = {
          price: price.toFixed(2),
          track: trackEvent.track_value,
          spaces: spaces.toFixed(0),
          limitedSpaces: limitedSpaces,
          criticalSpaces: criticalSpaces,
          bookingUrl: bookingUrl,
          description: description,
          date: trackEvent.date,
          dateFriendly: dateFriendly,
          dateObject: eventDate,
          group: trackEvent.group_value
        };

        events.push(newEvent);

        // Track statistics by track name
        if (!trackCount[trackEvent.track_value]) {
          trackCount[trackEvent.track_value] = 0;
        }
        trackCount[trackEvent.track_value]++;

      } catch (error) {
        console.error(`Error processing event ${key}:`, error.message);
      }
    });

    if (events.length === 0) return;

    // Sort events chronologically if feature is enabled
    if (config.features.sortChronologically) {
      events.sort((a, b) => a.dateObject - b.dateObject);
    }

    // Group events by date
    const eventsByDate = {};

    events.forEach(event => {
      const date = event.date;

      if (!eventsByDate[date]) {
        eventsByDate[date] = [];
      }

      eventsByDate[date].push(event);
    });

    // Store events for this track
    const trackName = events[0].track;
    eventsData[trackName] = eventsByDate;
  });

  // Add summary statistics
  const summary = {
    totalEvents: totalEvents,
    totalTracks: Object.keys(eventsData).length,
    limitedSpacesCount: limitedSpacesCount,
    criticalSpacesCount: criticalSpacesCount,
    trackBreakdown: trackCount,
    generatedAt: new Date().toISOString()
  };

  console.log('Aggregation complete:', summary);

  // Return in proper array format as requested
  return [{
    json: {
      eventsData: eventsData,
      summary: summary
    }
  }];

} catch (error) {
  console.error('Error in Aggregate Events Data:', error.message);
  throw new Error(`Event aggregation failed: ${error.message}`);
}

// Generate HTML Email (Enhanced)
// Mobile-responsive with summary statistics and booking links
// Fixed to work with pinned data - no external node references

try {
  // Get input data without using .first() or .item() methods
  const items = $input.all();

  if (!items || items.length === 0) {
    throw new Error('No input data received');
  }

  const item = items[0].json;
  const eventsData = item.eventsData;
  const summary = item.summary;

  // Hardcoded configuration (copied from Configuration node)
  // This avoids needing to reference the Configuration node which causes issues with pinned data
  const config = {
    features: {
      includeSummaryStats: true,
      includeBookingLinks: true,
      mobileResponsive: true
    },
    email: {
      styles: {
        primaryColor: '#3498db',
        secondaryColor: '#2c3e50',
        successColor: '#27ae60',
        warningColor: '#f39c12',
        dangerColor: '#cc0000',
        lightBg: '#ecf0f1',
        darkBg: '#34495e'
      }
    },
    api: {
      baseUrl: 'https://www.nolimitstrackdays.com'
    }
  };

  const styles = config.email.styles;

  let html = '';

  // Summary Statistics Section (if enabled)
  if (config.features.includeSummaryStats && summary) {
    html += `
    <div style="background: linear-gradient(135deg, ${styles.primaryColor} 0%, ${styles.secondaryColor} 100%); color: #ffffff; padding: 32px 24px; margin-bottom: 24px; border-radius: 8px; text-align: center; box-shadow: 0 4px 6px rgba(0,0,0,0.1);">
      <h2 style="margin: 0 0 20px 0; font-size: 24px; font-family: Arial, sans-serif; font-weight: bold;">📊 Summary</h2>
      <div style="display: block; width: 100%;">
        <div style="background: rgba(255,255,255,0.15); padding: 10px 24px; border-radius: 6px; margin-bottom: 8px;">
          <div style="font-size: 28px; font-weight: bold; margin-bottom: 4px;">${summary.totalEvents}</div>
          <div style="font-size: 13px; opacity: 0.9;">Total Events</div>
        </div>
        <div style="background: rgba(255,255,255,0.15); padding: 10px 24px; border-radius: 6px; margin-bottom: 8px;">
          <div style="font-size: 28px; font-weight: bold; margin-bottom: 4px;">${summary.totalTracks}</div>
          <div style="font-size: 13px; opacity: 0.9;">Tracks</div>
        </div>
        <div style="background: rgba(255,255,255,0.15); padding: 10px 24px; border-radius: 6px; margin-bottom: 8px;">
          <div style="font-size: 28px; font-weight: bold; margin-bottom: 4px; color: ${styles.warningColor};">${summary.limitedSpacesCount}</div>
          <div style="font-size: 13px; opacity: 0.9;">Limited spaces</div>
        </div>
        <div style="background: rgba(255,255,255,0.15); padding: 10px 24px; border-radius: 6px;">
          <div style="font-size: 28px; font-weight: bold; margin-bottom: 4px; color: ${styles.dangerColor};">${summary.criticalSpacesCount}</div>
          <div style="font-size: 13px; opacity: 0.9;">Last Spaces</div>
        </div>
      </div>
    </div>
    `;
  }

  // Mobile-responsive CSS
  const responsiveStyles = config.features.mobileResponsive ? `
    <style>
      @media only screen and (max-width: 600px) {
        .track-table { width: 100% !important; }
        .track-header { font-size: 18px !important; padding: 14px 16px !important; }
        .date-row { font-size: 14px !important; padding: 12px 16px !important; }
        .column-header { font-size: 12px !important; padding: 10px 8px !important; }
        .data-cell { font-size: 13px !important; padding: 12px 8px !important; }
        .description-cell { display: block; max-width: 100%; word-wrap: break-word; }
        .booking-link { display: inline-block; margin-top: 8px; padding: 8px 16px; background: ${styles.primaryColor}; color: #ffffff; text-decoration: none; border-radius: 4px; font-size: 12px; }
      }
    </style>
  ` : '';

  html = responsiveStyles + html;

  // Build events table
  let rows = '';
  const tracks = Object.entries(eventsData);

  for (const track of tracks) {
    const trackName = track[0];
    const trackDates = Object.keys(track[1]);

    // Track header with clean border design
    rows += `
    <tr>
      <td colspan="6" class="track-header" style="background-color: ${styles.secondaryColor}; color: #ffffff; padding: 18px 24px; font-size: 20px; font-weight: bold; font-family: Arial, sans-serif; text-align: left; border-top: 4px solid ${styles.primaryColor};">
        🏁 ${trackName}
      </td>
    </tr>`;

    trackDates.forEach(date => {
      const dateEvents = track[1][date];

      // Date row with left accent
      rows += `
      <tr>
        <td colspan="6" class="date-row" style="background-color: ${styles.lightBg}; color: ${styles.secondaryColor}; padding: 14px 24px; font-size: 15px; font-weight: bold; font-family: Arial, sans-serif; border-left: 5px solid ${styles.primaryColor};">
          📅 ${dateEvents[0].dateFriendly}
        </td>
      </tr>`;

      // Column headers with subtle styling
      rows += `
      <tr>
        <td class="column-header" style="background-color: ${styles.darkBg}; color: #ffffff; padding: 12px 16px; font-weight: bold; font-size: 13px; font-family: Arial, sans-serif; text-align: left;">Group</td>
        <td class="column-header" style="background-color: ${styles.darkBg}; color: #ffffff; padding: 12px 16px; font-weight: bold; font-size: 13px; font-family: Arial, sans-serif; text-align: left;">Price</td>
        <td class="column-header" style="background-color: ${styles.darkBg}; color: #ffffff; padding: 12px 16px; font-weight: bold; font-size: 13px; font-family: Arial, sans-serif; text-align: center;">Spaces</td>
        <td class="column-header" style="background-color: ${styles.darkBg}; color: #ffffff; padding: 12px 16px; font-weight: bold; font-size: 13px; font-family: Arial, sans-serif; text-align: left;">Description</td>
        <td class="column-header" style="background-color: ${styles.darkBg}; color: #ffffff; padding: 12px 16px; font-weight: bold; font-size: 13px; font-family: Arial, sans-serif; text-align: center;">Limited</td>
        <td class="column-header" style="background-color: ${styles.darkBg}; color: #ffffff; padding: 12px 16px; font-weight: bold; font-size: 13px; font-family: Arial, sans-serif; text-align: center;"></td>
      </tr>`;

      // Data rows with alternating backgrounds
      let rowIndex = 0;
      dateEvents.forEach(event => {
        const bgColor = rowIndex % 2 === 0 ? '#ffffff' : '#f8f9fa';
        let limitedColor = styles.successColor;
        let limitedText = 'No';

        if (event.criticalSpaces) {
          limitedColor = styles.dangerColor;
          limitedText = '⚠️ Last';
        } else if (event.limitedSpaces) {
          limitedColor = styles.warningColor;
          limitedText = '⚡ Yes';
        }

        // Booking link
        const bookingLinkHtml = config.features.includeBookingLinks
          ? `<a href="${event.bookingUrl}" class="booking-link" style="display: inline-block; padding: 8px 16px; background: ${styles.primaryColor}; color: #ffffff; text-decoration: none; border-radius: 4px; font-size: 12px; font-weight: bold;">Book Now</a>`
          : '-';

        // Add booking link to description if enabled
        const descriptionWithLink = config.features.includeBookingLinks
          ? `${event.description}`
          : event.description;

        rows += `
        <tr>
          <td class="data-cell" style="background-color: ${bgColor}; padding: 14px 16px; color: ${styles.secondaryColor}; font-family: Arial, sans-serif; font-size: 14px; border-bottom: 1px solid #e0e0e0;">${event.group}</td>
          <td class="data-cell" style="background-color: ${bgColor}; padding: 14px 16px; color: #16a085; font-family: Arial, sans-serif; font-size: 14px; font-weight: bold; border-bottom: 1px solid #e0e0e0;">£${event.price}</td>
          <td class="data-cell" style="background-color: ${bgColor}; padding: 14px 16px; color: #7f8c8d; font-family: Arial, sans-serif; font-size: 14px; text-align: center; border-bottom: 1px solid #e0e0e0; font-weight: bold;">${event.spaces}</td>
          <td class="data-cell description-cell" style="background-color: ${bgColor}; padding: 14px 16px; color: #34495e; font-family: Arial, sans-serif; font-size: 14px; border-bottom: 1px solid #e0e0e0;">${descriptionWithLink}</td>
          <td class="data-cell" style="background-color: ${bgColor}; padding: 14px 16px; color: ${limitedColor}; font-family: Arial, sans-serif; font-size: 13px; font-weight: bold; text-align: center; border-bottom: 1px solid #e0e0e0;">${limitedText}</td>
          <td class="data-cell" style="background-color: ${bgColor}; padding: 14px 16px; text-align: center; border-bottom: 1px solid #e0e0e0;">${bookingLinkHtml}</td>
        </tr>`;

        rowIndex++;
      });
    });

    // Spacer between tracks (outside the table)
    rows += `
    </table>
  </div>
  <div style="height: 32px; background-color: transparent;">&nbsp;</div>
  <div style="overflow-x: auto; -webkit-overflow-scrolling: touch;">
    <table class="track-table" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse: collapse; font-family: Arial, sans-serif; max-width: 1200px; margin: 0 auto; background-color: #ffffff; border: 1px solid #dcdcdc; box-shadow: 0 2px 8px rgba(0,0,0,0.1);">`;
  }

  // Build complete table with responsive wrapper
  const tableHtml = `
  <div style="overflow-x: auto; -webkit-overflow-scrolling: touch;">
    <table class="track-table" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse: collapse; font-family: Arial, sans-serif; max-width: 1200px; margin: 0 auto; background-color: #ffffff; border: 1px solid #dcdcdc; box-shadow: 0 2px 8px rgba(0,0,0,0.1);">
      ${rows}
    </table>
  </div>`;

  html += tableHtml;

  // Add footer
  html += `
  <div style="text-align: center; padding: 24px; color: #7f8c8d; font-family: Arial, sans-serif; font-size: 12px; margin-top: 24px;">
    <p style="margin: 0 0 8px 0;">Generated on ${new Date().toLocaleDateString('en-GB', { year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' })}</p>
    <p style="margin: 0;">© No Limits Track Days | <a href="${config.api.baseUrl}" style="color: ${styles.primaryColor}; text-decoration: none;">Visit Website</a></p>
  </div>`;

  console.log('HTML email generated successfully');

  return [{ json: { html } }];

} catch (error) {
  console.error('Error in Generate HTML Email:', error.message);
  throw new Error(`HTML generation failed: ${error.message}`);
}
